  ('cpa-moex-01705', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵法第20條規定，依稅法規定逾期繳納稅捐應加徵滯納金者，逾30日仍未繳納時，應如何？', '["加徵滯報金", "加徵怠報金", "加計利息", "移送強制執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01706', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '納稅義務人收到繳款書時，發現文書內計算錯誤，繳納期限最後一日為5月15日，納稅義務人可於5月 15日以前要求稅捐稽徵機關如何處理？', '["查對更正繳款書", "重寄繳款書", "重行復查", "逕行撤案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01707', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '現行稅捐稽徵法所稱之稅捐，包括下列何者？', '["關稅", "礦稅", "筵席稅", "菸酒稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01708', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵機關對有關復查之申請，於接到申請書後，稅捐稽徵機關未於法定期間內作成決定，並通知納 稅義務人，納稅義務人得逕行提起下列何項救濟程序？', '["民事訴訟", "再訴願", "訴願", "行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01709', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '張三將現金2,000萬元及公告土地現值1,000萬元之土地贈與李四，李四依贈與契約之約定，償付張三以 該筆土地抵押之借款1,200萬元，請問依遺產及贈與稅法施行細則規定，本案贈與附有負擔可扣除之金額 為多少？', '["800萬元", "1,000萬元", "1,200萬元", "1,800萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01710', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '遺產稅或贈與稅納稅義務人具有正當理由不能如期申報者，應於規定限期屆滿前，以書面申請延長之； 若無不可抗力或其他有特殊之事由者，其申請延長期限以多久為限？', '["1個月", "2個月", "3個月", "6個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01711', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，財產之買賣在下列何種情形，如無法提出支付價款之確實證明，將以贈與論， 依法課徵贈與稅？', '["伯父與侄兒之間", "夫妻之間", "姐妹之間", "朋友之間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01712', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，被繼承人如為經常居住中華民國境內之中華民國國民，但非為軍警公教人員因 執行職務死亡者，於98年1月23日以後死亡時，其免稅額為多少？', '["700萬元", "779萬元", "1,200萬元", "1,400萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01713', 'cpa', 'cpa-moex-101-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '將作農業使用之農業用地及其地上農作物，贈與民法第1138條所定繼承人者，其土地及地上農作物價值 之全數不計入贈與總額。若受贈人自受贈之日起幾年內，未將該土地繼續作農業使用且未在有關機關所 令期限內恢復作農業使用，或雖在有關機關所令期限內已恢復作農業使用而再有未作農業使用情事者， 應追繳應納稅賦？', '["1年", "2年", "3年", "5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "0ad5d567b1f5", "answer_pdf_sha1": "080c857f8e94", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01714', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '荔枝公司於X1年1月1日藉由契約協議取得對其供應商雪梨公司之控制，並使荔枝公司所需之技術 支援更為穩定、並減少存貨庫存，估計此項利益之公允價值為$80,000。荔枝公司並未持有雪梨公司 之任何股權。X1 年初雪梨公司股票之總市值為$320,000，可辨認淨資產之公允價值為$300,000。若 依可辨認淨資產比例衡量非控制權益，此無對價合併所產生之商譽為：', '["0", "$20,000", "$60,000", "$80,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01715', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '橘子公司於X6年4月1日以換發新股方式吸收合併蘋果公司，橘子公司為存續公司，換股比例為每 1股蘋果公司股票，換發橘子公司股票2股。X6年3月31日橘子公司及蘋果公司流通在外之普通股 分別為20,000股及40,000股。橘子公司X6年之淨利為$950,000，該公司X6年每股盈餘為何？', '["$8.53", "$10", "$11.25", "$12"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01716', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '秀岡公司於X5年1月1日取得青宇公司80%股權，當時青宇公司各項可辨認資產、負債之帳面金額 均等於公允價值，且無合併商譽。青宇公司於X6年1月1日增資發行新股5,000股，每股發行價格 $12，秀岡公司認購 1000 股外，均由其他個體購得。青宇公司增資前權益包括普通股股本（每股面 額$10）$450,000及保留盈餘$180,000。秀岡公司採權益法處理對青宇公司之投資，青宇公司增資發 行新股時，秀岡公司帳上應調整資本公積之金額為何？', '["增加$4,440", "減少$4,440", "增加$5,400", "減少$5,400"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01717', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年1月1日大金公司以$68,000購入小山公司15%股權，當日小山公司權益為$500,000。大金公司 於X2年10月1日以$540,000另取得小山公司65%股權，並改採權益法處理對小山公司之投資，當 時小山公司各項可辨認資產、負債之帳面金額均與公允價值相等，原持有小山公司 15%股權之公允 價值為$112,000。小山公司X1年及X2年淨利分別為$72,000及$80,000，股利分別為$20,000及$30,000 （係於每年6月1日發放）。大金公司X2年底「投資小山公司」帳戶餘額及X2年投資收益（含股 利收入）分別為何？', '["$668,000及$16,000", "$608,000及$16,000", "$668,000及$20,500", "$608,000及$24,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01718', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '紐約公司於X1年1月1日與洋基公司簽訂技術合約，授權洋基公司使用紐約公司之某項技術，合約 期限為9年，不得展延。紐約公司於X5年1月1日以現金$500,000吸收合併洋基公司，當日洋基公 司可辨認淨資產之公允價值包括：與紐約公司所簽訂之技術合約$100,000、其他可辨認資產$740,000 及負債$320,000。該技術合約條件對紐約公司而言較市場條件不利，不利之金額為$80,000。合約規 定不得提前解約且紐約公司於收購日前並未針對此不利狀況認列任何資產或負債。紐約公司有關之 會計處理，下列敘述何者正確？', '["X5年1月1日應認列之技術合約結清損失$80,000", "X5年1月1日應認列「再取回之權利－技術合約」$80,000", "X5年1月1日應認列之合併商譽為$80,000", "X5年1月1日企業合併之移轉對價為$520,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01719', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，X6年1月1日紐約公司將收購日所取回之技術合約以$100,000售予尼克公司。當日紐約公 司應認列出售該技術合約之（損）益為何？', '["$80,000", "$60,000", "$20,000", "$10,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01720', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司持有乙公司90%股權，乙公司持有丙公司70%股權，聯屬公司間投資均以投資日股權淨值取 得。本年度各公司個別淨利如下：甲公司$120,000；乙公司$60,000；丙公司$30,000。試問合併淨利 與非控制權益淨利為何？', '["$180,900與$29,100", "$192,900與$17,100", "$195,000與$15,000", "$198,900與$11,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01721', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '書豪公司於X1年底以$150,000的價格出售機器予其持股80%的建明公司。該機器對書豪公司而言，成 本為$200,000，出售當時的帳面金額為$120,000，該機器尚有5年的耐用年限，採直線法提列折舊。書 豪公司對該項投資採權益法處理，此一公司間銷售對X1年的投資收益及書豪公司帳列淨利的影響為 何？', '["投資收益減少$30,000，不影響書豪公司帳列淨利", "投資收益與書豪公司帳列淨利同時減少$30,000", "投資收益減少$24,000，書豪公司帳列淨利增加$6,000", "投資收益減少$24,000，書豪公司帳列淨利增加$24,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01722', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日分別持有乙公司與丙公司60%與30%之股權，乙公司於同日持有丙公司40% 股權，前述各項投資皆採權益法處理，且於該日均無未攤銷差額。甲、乙與丙三家公司於X1年之個 別淨利（不含投資收益或股利收入）分別為$1,000,000、$500,000與$200,000。丙公司於X1年10月 1日以$200,000銷售商品予甲公司，該批商品於丙公司帳列存貨成本為$150,000。截至X1年底，甲 公司購自丙公司該批存貨仍有半數尚未出售予外部企業。試問在X1年甲公司及其子公司之合併損益 表上，非控制權益淨利為：', '["$228,000", "$252,500", "$280,500", "$292,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01723', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '大為公司定期銷售商品予其持股 90%之子公司小城公司。小城公司 X1 年底的期末存貨中，包含 $40,000之未實現銷貨毛利，而X2年底的期末存貨中，則包含$30,000之未實現銷貨毛利，則下列敘 述何者正確？', '["X2年大為公司和小城公司個別銷貨成本的合計數將小於合併銷貨成本", "X2年大為公司和小城公司個別銷貨收入的合計數將小於合併銷貨收入", "X2年底大為公司和小城公司個別存貨的合計數將小於合併存貨", "X2年大為公司和小城公司個別銷貨毛利的合計數將小於合併銷貨毛利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01724', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日以$600,000取得乙公司60%之股權，當日乙公司權益包括股本$500,000（每 股面額$10），保留盈餘$400,000，除建築物低估$50,000（剩餘效益年限為 10 年，採直線法折舊） 外，當日乙公司其他可辨認資產與負債之帳面金額均等於公允價值。甲公司依可辨認淨資產之比例 衡量非控制權益。X2年12月31日乙公司之權益包括股本$500,000，保留盈餘$610,000。乙公司於 X3年1月1日以每股$23向非控制權益股東買回10,000股自家股份。甲公司採權益法處理其對乙公 司之投資。試問在X3年1月1日乙公司買回庫藏股後，甲公司帳上「投資乙公司」之帳戶餘額為：', '["$690,000", "$696,000", "$720,000", "$726,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01725', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日以$480,000 取得上市公司乙公司 40%之股權，當日乙公司之權益為 $1,000,000，且其所有可辨認資產與負債之帳面金額均等於公允價值。甲公司於X1年7月1日另以 市價$500,000 額外取得乙公司 40%之股權，當日乙公司所有可辨認資產與負債中，除了存貨高估 $45,000外，其他可辨認資產與負債之帳面金額均等於公允價值，該批存貨於X1年12月31日仍有 1/3 尚未出售。甲公司依可辨認淨資產比例衡量非控制權益。乙公司 X1 年之淨利為$180,000，係於 年度中平均賺得。乙公司於X1年6月10日發放現金股利$45,000。甲公司採權益法處理該項投資。 試問X1年12月31日合併商譽與投資乙公司之帳戶餘額分別為：', '["$180,000與$1,094,000", "$200,000與$1,048,000", "$198,000與$1,094,000", "$200,000與$1,096,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
